#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

     uvq=vUv-.5;
     brad= length(uvq);
     bang = atan(uvq.x,uvq.y);
    col=1+(1/vec3(1,2,3))+(.5+.5*sin(uTime/(93+audioMidSmooth+audioLow+audioLowSmooth-audioHigh-audioHighSmooth)));
    col.x-=int(col.x);
    col.y-=int(col.y);
    col.z-=int(col.z);
// darken (decay) over uTime
    ret *= 0.92+.05*(col); //or try: ret -= 0.004;
ret =max(1*(0.6+0.3*sin(bang-brad+uFrame/uFps+audioLowSmooth-audioHighSmooth%uFrame/1000/uFrame))- tex2d(sampler_rand01,vUvOriginal)
,1*(0.6+0.3*cos(bang-brad+uFrame/uFps+audioLowSmooth-audioHighSmooth%uFrame/1000/uFrame))- tex2d(sampler_rand02 ,vUvOriginal));
//ret +=1*(0.7+0.3*cos(uFrame/uFps+audioMidSmooth+audioLowSmooth%uFrame/1000/uFrame))- tex2d(sampler_rand02 ,vUvOriginal);
ret *=.91;
//ret=1-ret;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;
vUv = (vUv-0.5);
factorA = vUv+ vec2(q11,q12);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv1 = product;
factorA = vUv+ vec2(q13,q14);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv2 = product;
factorA = vUv+ vec2(q15,q16);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv3 = product;
factorA = vUv+ vec2(q17,q18);
factorB = vec2(8,0);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv4 = product;
factorA = uv1;
factorB = uv2;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv12 = product;
factorA = uv3;
factorB = uv4;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 uv34 = product;
factorA = uv12;
factorB = uv34;
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
numerator = vec2(1,0);
denominator = product;
fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction*2;
vUv = mix(0.5 + (uvo-0.5)*(2+(audioLowSmooth-audioHighSmooth)*0.02),vUv+0.5,0.5);

float l = length(vUv-0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5); // Eo.S. mirror code with cutted borders
    ret = texture(sampler_main, vUv).xyz;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
      // SUPER GLOW EDGES - looks awesome w/octopus
      vec3 avg_col = GetBlur3(vUv+.01*(audioLow+audioMid+audioHigh));
      ret = abs(avg_col*.5 - (.7-ret));
//    ret *= 1.333; // a little bit of overbright
ret = mix(ret,0,l*l*l);

  fragColor = ret;
}
